mapper.update:
UPDATE 	test_process

SET 	status = #{status, jdbcType=VARCHAR}

WHERE 	test_process_code = #{testProcessCode, jdbcType=VARCHAR}

UPDATE work_progress
SET prod_quantity = CASE WHEN #{prodQuantity} IS NULL THEN prod_quantity ELSE #{prodQuantity} END, error_quantity = CASE WHEN #{errorQuantity} IS NULL THEN error_quantity ELSE #{errorQuantity} END, input_quantity = CASE WHEN #{inputQuantity} IS NULL THEN input_quantity ELSE #{inputQuantity} END, instruct_quantity = CASE WHEN #{instructQuantity} IS NULL THEN instruct_quantity ELSE #{instructQuantity} END
WHERE work_progress_code = #{workProgressCode}

UPDATE 	work_progress

SET 	instruct_quantity = #{prodQuantity}

WHERE 	work_instruct_detail_code = #{workInstructDetailCode}
AND 	proc_num = #{procNum}

UPDATE 	work_progress

SET 	progress = 'Y'

WHERE 	work_instruct_detail_code = #{workInstructDetailCode}

AND 	work_progress_code = #{workProgressCode}

mapper.select:
SELECT 	progress

FROM 	work_progress

WHERE 	work_instruct_detail_code = #{workInstructDetailCode}
AND proc_num < #{procNum} 
AND progress != 'Y'

SELECT 	COUNT(*)

FROM 	work_progress

WHERE 	work_instruct_detail_code = #{workInstructDetailCode}
AND 	proc_num < #{procNum}

select test_code, test_name, test_item, test_item_unit, note FROM test WHERE
AND testName = #{inputVal}
AND fac_class_code = #{inputVal}
ORDER BY test_num
